    private readonly LoginDto _loginDto = new();
    private bool _rememberMe = false;
    private bool _isLoading = false;

    private async Task HandleLogin()
    {
        try
        {
            _isLoading = true;
            var result = await AuthService.LoginAsync(_loginDto);

            if (result.IsSuccess)
            {
                Snackbar.Add("Erfolgreich angemeldet!", Severity.Success);
                Navigation.NavigateTo("/dashboard", forceLoad: true);
            }
            else
            {
                Snackbar.Add($"Anmeldung fehlgeschlagen: {result.Error}", Severity.Error);
            }
        }
        catch (Exception ex)
        {
            Snackbar.Add($"Ein Fehler ist aufgetreten: {ex.Message}", Severity.Error);
        }
        finally
        {
            _isLoading = false;
        }
    }

    protected override async Task OnInitializedAsync()
    {
        if (await AuthService.IsAuthenticatedAsync())
        {
            Navigation.NavigateTo("/dashboard");
        }
    }

